mapper.select:
SELECT pgeo.id, pgeo.excluded_object_id, pgeo.object_type, CASE pgeo.object_type WHEN 'user' THEN '用户' WHEN 'org' THEN '组织' WHEN 'station' THEN '驻地' WHEN 'position' THEN '岗位' ELSE pgeo.object_type END AS object_type_name, pgeo.excluded_object_id AS object_id, CASE pgeo.object_type WHEN 'user' THEN (SELECT u.user_name FROM po_users u WHERE u.user_id = pgeo.excluded_object_id) WHEN 'org' THEN (SELECT o.org_name FROM po_organization o WHERE o.org_id = pgeo.excluded_object_id) ELSE NULL END AS object_name, pgeo.effective_at, pgeo.expires_at, pgeo.create_time, pgeo.create_by, u.user_name AS create_by_name FROM permission_group_excluded_objects pgeo LEFT JOIN po_users u ON pgeo.create_by = u.user_id
pgeo.permission_group_id = #{query.permissionGroupId}
AND pgeo.object_type = #{query.objectType}
AND ( (pgeo.object_type = 'user' AND EXISTS ( SELECT 1 FROM po_users us WHERE us.user_id = pgeo.excluded_object_id AND us.user_name LIKE CONCAT('%', #{query.objectName}, '%') )) OR (pgeo.object_type = 'org' AND EXISTS ( SELECT 1 FROM po_organization os WHERE os.org_id = pgeo.excluded_object_id AND os.org_name LIKE CONCAT('%', #{query.objectName}, '%') )) )
ORDER BY pgeo.create_time DESC

